<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Maze Pathfinding Bots</title>
    <style>
        body {
            margin: 0;
            padding: 20px;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            background-color: #1a1a1a;
            color: #eee;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
        }
        #hud {
            display: flex;
            gap: 40px;
            margin-bottom: 20px;
            background: #333;
            padding: 15px 30px;
            border-radius: 8px;
            box-shadow: 0 4px 15px rgba(0,0,0,0.5);
            font-size: 1.2rem;
            font-weight: bold;
        }
        .hud-item {
            display: flex;
            align-items: center;
            gap: 10px;
        }
        #maze-container {
            position: relative;
            border: 4px solid #444;
            border-radius: 4px;
            box-shadow: 0 0 20px rgba(0,0,0,0.8);
            background-color: #000;
        }
        canvas {
            display: block;
        }
        #controls {
            margin-top: 20px;
        }
        button {
            padding: 10px 25px;
            font-size: 1rem;
            cursor: pointer;
            background-color: #e74c3c;
            color: white;
            border: none;
            border-radius: 4px;
            transition: background 0.2s, transform 0.1s;
        }
        button:hover {
            background-color: #c0392b;
        }
        button:active {
            transform: scale(0.95);
        }
    </style>
</head>
<body>

    <div id="hud">
        <div class="hud-item">Completed: <span id="completed">0</span>/24</div>
        <div class="hud-item">Time: <span id="timer">0</span>ms</div>
    </div>

    <div id="maze-container">
        <canvas id="maze" width="500" height="500"></canvas>
    </div>

    <div id="controls">
        <button id="reset">Reset Game</button>
    </div>

    <script>
        /** 
         * Maze Generation & Pathfinding Logic
         */
        function generateMaze(size) {
            const grid = Array(size).fill().map(() => Array(size).fill(1));
            const stack = [[1, 1]];
            grid[1][1] = 0;

            while (stack.length > 0) {
                const [r, c] = stack[stack.length - 1];
                const neighbors = [];
                const dirs = [[0, 2], [0, -2], [2, 0], [-2, 0]];

                for (const [dr, dc] of dirs) {
                    const nr = r + dr, nc = c + dc;
                    if (nr > 0 && nr < size - 1 && nc > 0 && nc < size - 1 && grid[nr][nc] === 1) {
                        neighbors.push([nr, nc]);
                    }
                }

                if (neighbors.length > 0) {
                    const [nr, nc] = neighbors[Math.floor(Math.random() * neighbors.length)];
                    grid[nr][nc] = 0;
                    grid[r + (nr - r) / 2][c + (nc - c) / 2] = 0;
                    stack.push([nr, nc]);
                } else {
                    stack.pop();
                }
            }
            return grid;
        }

        function findPath(grid, start, end) {
            const queue = [[start]];
            const visited = new Set([start[0] + ',' + start[1]]);
            while (queue.length > 0) {
                const path = queue.shift();
                const [r, c] = path[path.length - 1];
                if (r === end[0] && c === end[1]) return path;

                for (const [dr, dc] of [[0, 1], [0, -1], [1, 0], [-1, 0]]) {
                    const nr = r + dr, nc = c + dc;
                    if (nr >= 0 && nr < grid.length && nc >= 0 && nc < grid[0].length &&
                        grid[nr][nc] === 0 && !visited.has(nr + ',' + nc)) {
                        visited.add(nr + ',' + nc);
                        queue.push([...path, [nr, nc]]);
                    }
                }
            }
            return [];
        }

        /**
         * Game Engine
         */
        class MazeGame {
            constructor() {
                this.stepDuration = 50; // ms per simulation step
                this.canvas = document.getElementById('maze');
                this.ctx = this.canvas.getContext('2d');
                this.completedEl = document.getElementById('completed');
                this.timerEl = document.getElementById('timer');
                this.reset();
            }

            reset() {
                this.gridSize = 31; // Odd number for wall-based generation
                this.grid = generateMaze(this.gridSize);
                this.startPos = [1, 1];
                this.endPos = [29, 29];
                this.exitX = 29;
                this.exitY = 29;
                this.path = findPath(this.grid, this.startPos, this.endPos);

                this.bots = [];
                for (let i = 0; i < 24; i++) {
                    this.bots.push({
                        x: 1, // column index
                        y: 1, // row index
                        pathIndex: 0,
                        finished: false,
                        delay: i // Staggered start to prevent "blob" movement
                    });
                }

                this.completedCount = 0;
                this.internalStepCount = 0;
                this.render();
            }

            tick(n) {
                for (let i = 0; i < n; i++) {
                    this.step();
                }
            }

            step() {
                this.internalStepCount++;
                for (let i = 0; i < this.bots.length; i++) {
                    const bot = this.bots[i];
                    if (!bot.finished && this.internalStepCount > bot.delay) {
                        const nextIdx = bot.pathIndex + 1;
                        if (nextIdx < this.path.length) {
                            bot.pathIndex = nextIdx;
                            const [nr, nc] = this.path[nextIdx];
                            bot.x = nc; // Update cell column
                            bot.y = nr; // Update cell row
                            if (bot.x === this.exitX && bot.y === this.exitY) {
                                bot.finished = true;
                                this.completedCount++;
                            }
                        }
                    }
                }
            }

            get completed() { return this.completedCount; }
            get elapsedMs() { return this.internalStepCount * this.stepDuration; }

            render() {
                const ctx = this.ctx;
                const cellSize = this.canvas.width / this.gridSize;
                ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);

                // Draw Walls and Paths
                for (let r = 0; r < this.gridSize; r++) {
                    for (let c = 0; c < this.gridSize; c++) {
                        ctx.fillStyle = this.grid[r][c] === 1 ? '#333' : '#000';
                        ctx.fillRect(c * cellSize, r * cellSize, cellSize + 0.5, cellSize + 0.5);
                    }
                }

                // Draw Exit
                ctx.fillStyle = '#2ecc71';
                ctx.fillRect(this.exitX * cellSize, this.exitY * cellSize, cellSize, cellSize);

                // Draw Bots
                this.bots.forEach((bot, idx) => {
                    ctx.fillStyle = bot.finished ? '#555' : `hsl(${(idx * 15) % 360}, 70%, 60%)`;
                    ctx.beginPath();
                    const centerX = bot.x * cellSize + cellSize / 2;
                    const centerY = bot.y * cellSize + cellSize / 2;
                    ctx.arc(centerX, centerY, cellSize * 0.35, 0, Math.PI * 2);
                    ctx.fill();
                });

                // Update HUD
                this.completedEl.textContent = this.completedCount;
                this.timerEl.textContent = this.elapsedMs;
            }
        }

        const game = new MazeGame();
        window.game = game; // Expose for automated testing

        // Animation Loop
        let lastTime = 0;
        function animate(time) {
            if (!lastTime) lastTime = time;
            const deltaTime = time - lastTime;

            // Run simulation steps based on elapsed real-world time
            if (deltaTime >= game.stepDuration) {
                const stepsToRun = Math.floor(deltaTime / game.stepDuration);
                game.tick(stepsToRun);
                lastTime = time - (deltaTime % game.stepDuration);
            }

            game.render();
            requestAnimationFrame(animate);
        }

        // Event Listeners
        document.getElementById('reset').addEventListener('click', () => {
            game.reset();
        });

        requestAnimationFrame(animate);
    </script>
</body>
</html>
